document.addEventListener("DOMContentLoaded",function(){const t=document.querySelector(".payment__payments");if(!t)return;function n(){t.querySelectorAll(".form-check").forEach(function(e){const c=e.querySelector('.form-check-input[type="radio"][name="paymentid"]');if(!c)return;e.querySelectorAll(".form-check-label input, .form-check-label select, .form-check-label textarea").forEach(function(r){r.disabled=!c.checked})})}n(),t.addEventListener("change",function(e){e.target&&e.target.type==="radio"&&e.target.name==="paymentid"&&n()})});
